text:
{
  "title": "Kursus Pembinaan Rumah",
  "description": "Kursus ini direka untuk memberikan pengetahuan dan kemahiran asas dalam membina rumah, dengan fokus kepada bahan, proses, dan teknik yang diperlukan.",
  "modules": [
    {
      "id": "module_1",
      "title": "Pengenalan kepada Bahan Pembinaan",
      "description": "Pelajari tentang bahan-bahan yang biasa digunakan dalam pembinaan rumah, termasuk kayu, simen, bata, dan bahan moden lain. Aktiviti: Senaraikan bahan yang anda kenal dan bincangkan penggunaannya dalam kumpulan."
    },
    {
      "id": "module_2",
      "title": "Perancangan dan Reka Bentuk",
      "description": "Ketahui langkah-langkah awal dalam merancang dan merekabentuk rumah. Fokus kepada pengukuran, pelan lantai, dan keperluan asas. Aktiviti: Buat pelan lantai sederhana untuk rumah impian anda."
    },
    {
      "id": "module_3",
      "title": "Proses Pembinaan",
      "description": "Memahami langkah-langkah dalam proses pembinaan, dari asas hingga siap. Termasuk teknik pembinaan dan keselamatan. Aktiviti: Simulasi pembinaan menggunakan bahan kertas untuk memahami proses."
    },
    {
      "id": "module_4",
      "title": "Penyelesaian dan Penjagaan Rumah",
      "description": "Belajar tentang penyelesaian akhir dan penjagaan rumah selepas pembinaan. Termasuk pemilihan cat, perabot, dan penyelenggaraan. Aktiviti: Rancang penyelenggaraan rumah anda untuk tahun pertama."
    }
  ]
}
